    role: "Desarrollador",
    backType: "image",
    backContent: "/ruta/a/la/imagen3.jpg",
  },
];

const AboutUsContainer = () => {
  return (
    <main style={{ backgroundColor: "#f8f2e7", color: "#003E73", padding: "3rem 1rem" }}>
      <NosotrosSection />
      <ObjetivoSection />
      <MisionSection />
      <Carousel cardsData={cardsData} />
    </main>
  );
};

export default AboutUsContainer;
